const npc = $input.item.json;

const firstName = npc.firstName || npc.name?.split(' ')[0] || 'Unknown';
const lastName = npc.lastName || npc.name?.split(' ').slice(1).join(' ') || 'User';
const role = (npc.role || '').toLowerCase();
const country = (npc.country || '').toLowerCase();
const attributes = npc.attributes || {};

const roleKey = country + '/' + role;

const modelMap = {
  'valdoria/citizen': 'social-valdoria-citizen',
  'valdoria/military': 'social-valdoria-military',
  'valdoria/official': 'social-valdoria-official',
  'valdoria/media': 'social-media-reporter',
  'krasnovia/official': 'social-krasnovia-official',
  'krasnovia/media': 'social-media-reporter',
  'krasnovia/disguised': 'social-krasnovia-disguised',
  'krasnovia/bot': 'social-bot',
};

let model = modelMap[roleKey];
if (!model) {
  if (country === 'tarvek') {
    model = 'social-tarvek';
  } else if (country === 'arventa') {
    model = 'social-arventa';
  } else {
    model = 'qwen3.5:9b';
  }
}

const profileJson = JSON.stringify({
  firstName,
  lastName,
  role: npc.role,
  country: npc.country,
  attributes,
});

const prompt = `Write a short social media post (1-3 sentences) as this person. Profile: ${profileJson}. Post naturally on MeridiaNet.`;

const username = (firstName.charAt(0) + lastName).toLowerCase().replace(/[^a-z0-9_]/g, '');
const displayName = firstName + ' ' + lastName;
const npcId = npc.id;

return [{ json: { prompt, model, username, displayName, npcId } }];

const ollamaResponse = $input.item.json;
let content = ollamaResponse.response || ollamaResponse.text || '';

// Strip <think>...</think> tags
content = content.replace(/<think>[\s\S]*?<\/think>/g, '').trim();

// Truncate to 500 chars
if (content.length > 500) {
  content = content.substring(0, 497) + '...';
}

const username = $('Build Prompt').item.json.username;
const model = $('Build Prompt').item.json.model;
const npcId = $('Build Prompt').item.json.npcId;

const TOKEN_MAP = __NPC_TOKEN_MAP__;

const token = TOKEN_MAP[username];

if (!token) {
  console.log(`WARNING: No Mastodon token found for username: ${username}`);
  return [{ json: { mastodonPostId: null, username, content: '', model, error: 'No token found' } }];
}

if (!content) {
  console.log(`WARNING: Empty content for username: ${username}`);
  return [{ json: { mastodonPostId: null, username, content: '', model, error: 'Empty content' } }];
}

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://host.docker.internal:8000/api/v1/statuses',
  headers: {
    'Authorization': 'Bearer ' + token,
    'Content-Type': 'application/json',
  },
  body: JSON.stringify({ status: content }),
});

const mastodonPostId = response.id || null;

return [{ json: { mastodonPostId, username, content, model } }];
